data.content:
MSTest **does** have comparison assertions (MSTest 3.x+). Here's what's available:

```csharp
Assert.IsGreaterThan(lowerBound, actual);
Assert.IsLessThan(upperBound, actual);
Assert.IsInRange(actual, low, high);
```

Here's how to use them for your `ScoreCalculator`:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    [TestMethod]
    public void CalculatePercentage_AllCorrect_Returns100()
    {
        var result = _calculator.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsValueInRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(70.0, result);
    }

    [TestMethod]
    public void NormalizeScore_BelowMax_ReturnsPercentageInRange()
    {
        var result = _calculator.NormalizeScore(75, 150);
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(200, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(pct));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }
}
```

**Key points:**
- `Assert.IsInRange(actual, low, high)` — value is within bounds (inclusive)
- `Assert.IsGreaterThan(lowerBound, actual)` — actual exceeds the bound
- `Assert.IsLessThan(upperBound, actual)` — actual is below the bound
- Use `[DataRow]` for boundary values (89.9/90.0, 79.9/80.0, etc.) to test grade transitions concisely

These require **MSTest 3.x+** (the `MSTest` metapackage or `MSTest.Sdk`).
